import FormGroup from "@mui/material/FormGroup";
import FormControlLabel from "@mui/material/FormControlLabel";
import Checkbox from "@mui/material/Checkbox";
import RangeSlider from "react-range-slider-input";
import "react-range-slider-input/dist/style.css";
import { useState } from "react";

const Sidebar = () => {
  const [value, setValue] = useState([0, 9999999]);
  const [value2, setValue2] = useState(0);

  return (
    <>
      <div className="sidebar">
        <div className="filterBox">
          <h6>DANH MỤC SẢN PHẨM</h6>
          <div className="scroll">
            <ul>
              <li>
                <FormControlLabel
                  className="w-100"
                  control={<Checkbox />}
                  label="Nam"
                />
              </li>
              <li>
                <FormControlLabel
                  className="w-100"
                  control={<Checkbox />}
                  label="Nữ"
                />
              </li>
              <li>
                <FormControlLabel
                  className="w-100"
                  control={<Checkbox />}
                  label="Phụ kiện"
                />
              </li>

              <li>
                <FormControlLabel
                  className="w-100"
                  control={<Checkbox />}
                  label="Nam"
                />
              </li>
              <li>
                <FormControlLabel
                  className="w-100"
                  control={<Checkbox />}
                  label="Nữ"
                />
              </li>
              <li>
                <FormControlLabel
                  className="w-100"
                  control={<Checkbox />}
                  label="Phụ kiện"
                />
              </li>
            </ul>
          </div>
          <div className="filterBox">
            <h6>LỌC THEO GIÁ</h6>
            <RangeSlider
              value={value}
              onInput={setValue}
              min={0}
              max={9999999}
              step={10000}
            />
            <div className="d-flex pt-2 pb-2 priceRange">
              <span>
                Giá từ:{" "}
                <strong className="text-success"> {value[0]}VNĐ </strong>
              </span>
              <span className="ml-auto">
                đến: <strong className="text-success">VNĐ:{value[1]}</strong>
              </span>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};
export default Sidebar;
